parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "UCI": {
      "type": "string",
      "description": "Full client ID exactly as written in source text"
    },
    "student_name": {
      "type": "string",
      "description": "Full student name exactly as written in source text"
    },
    "guardian_name": {
      "type": "string",
      "description": "Full guardian name exactly as written in source text"
    },
    "authorization_comments": {
      "type": "string",
      "description": "Authorization comments extracted specifically from Service Details"
    },
    "authorization_date": {
      "type": "string",
      "description": "Authorization range formatted MM/DD/YY - MM/DD/YY"
    },
    "current_auth_exp_date": {
      "type": "string",
      "description": "Current authorization expiration date formatted MM/DD/YY"
    },
    "hours_per_month": {
      "type": "string",
      "description": "Format exactly like 30 hours/month (09/01/26 - 12/31/26)"
    },
    "requested_schedule": {
      "type": "string",
      "description": "Requested schedule format like 3pm-7pm M-Th virtual"
    },
    "parent_requested_mode_of_services": {
      "type": "string",
      "description": "Service mode only, e.g. virtual, in-person, hybrid"
    },
    "parent_feedback": {
      "type": "string",
      "description": "Parent feedback comments"
    },
    "start_date_track": {
      "type": "string",
      "description": "Preserve full original date format exactly, e.g. Mon Feb 01 2025 03:00:00 GMT-0800 (Pacific Standard Time)"
    }
  },
  "required": [
    "student_name",
    "guardian_name",
    "authorization_comments",
    "authorization_date",
    "current_auth_exp_date",
    "hours_per_month",
    "requested_schedule",
    "parent_requested_mode_of_services",
    "parent_feedback",
    "start_date_track"
  ]
}
